#!/usr/bin/env node
/**
 * generate-ci-proof.mjs
 *
 * Reads test-output/vitest.json (machine-generated by vitest --reporter=json)
 * and produces docs/ci-proof-artifact.md.
 *
 * Rules:
 *   - Every number in the output comes from vitest.json. No arithmetic, no "expected".
 *   - If vitest.json does not exist, exit 1 with instructions.
 *   - The generated markdown is deterministic given the same JSON input.
 *
 * Usage:
 *   node scripts/generate-ci-proof.mjs
 *   pnpm proof:generate
 */

import { readFileSync, writeFileSync, lstatSync, existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const JSON_PATH = join(ROOT, "test-output", "vitest.json");
const MD_PATH = join(ROOT, "docs", "ci-proof-artifact.md");

// ── Self-enforcing structural checks ─────────────────────────────────────────────────
const SPEC_SYMLINK_PATH = join(ROOT, "spec", "wazuh-api-v4.14.3.yaml");
try {
  const stat = lstatSync(SPEC_SYMLINK_PATH);
  if (!stat.isSymbolicLink()) {
    console.error("PROOF FAIL: spec/wazuh-api-v4.14.3.yaml is NOT a symlink.");
    console.error("Fix: rm spec/wazuh-api-v4.14.3.yaml && ln -s ../spec-v4.14.3.yaml spec/wazuh-api-v4.14.3.yaml");
    process.exit(1);
  }
  console.log("✓ spec/wazuh-api-v4.14.3.yaml is a symlink (canonical spec source verified)");
} catch {
  console.error("PROOF FAIL: spec/wazuh-api-v4.14.3.yaml does not exist.");
  process.exit(1);
}

const SEED_PATH = join(ROOT, "seed-kg.mjs");
try {
  const seedContent = readFileSync(SEED_PATH, "utf-8");
  if (seedContent.includes("Sync status:    4") || seedContent.includes("Sync status: 4")) {
    console.error("PROOF FAIL: seed-kg.mjs contains hardcoded sync status count.");
    console.error("Fix: replace with dynamic count from getLayerNames().length");
    process.exit(1);
  }
  console.log("✓ seed-kg.mjs has no hardcoded sync status magic numbers");
} catch {
  console.error("WARNING: seed-kg.mjs not found (non-fatal for proof generation)");
}

// ── Load vitest.json ────────────────────────────────────────────────────────────────
let raw;
try {
  raw = readFileSync(JSON_PATH, "utf-8");
} catch {
  // Chain-of-custody guard: if the markdown proof exists but the JSON source is missing,
  // the proof is unverifiable. Fail loudly.
  if (existsSync(MD_PATH)) {
    console.error("PROOF FAIL: docs/ci-proof-artifact.md exists but test-output/vitest.json is missing.");
    console.error("The proof document claims machine-generated counts from vitest.json.");
    console.error("Without the JSON, the chain of custody is broken.");
    console.error("Fix: run tests first, then regenerate proof:");
    console.error("  pnpm test -- --run --reporter=json --outputFile.json=test-output/vitest.json");
    console.error("  pnpm proof:generate");
    process.exit(1);
  }
  console.error("ERROR: test-output/vitest.json not found.");
  console.error("Run: pnpm test -- --run --reporter=json --outputFile.json=test-output/vitest.json");
  process.exit(1);
}

const report = JSON.parse(raw);

// ── Extract measured values ─────────────────────────────────────────────────
// vitest counts describe blocks as "suites", not files.
// We report both: file count from testResults.length, suite count from numTotalTestSuites.
const totalFiles = report.testResults.length;
const passedFiles = report.testResults.filter((t) => t.status === "passed").length;
const failedFiles = report.testResults.filter((t) => t.status === "failed").length;
const totalSuites = report.numTotalTestSuites;
const passedSuites = report.numPassedTestSuites;
const failedSuites = report.numFailedTestSuites;
const totalTests = report.numTotalTests;
const passedTests = report.numPassedTests;
const failedTests = report.numFailedTests;
const success = report.success;
const startTime = new Date(report.startTime).toISOString();

// Per-file breakdown
const files = report.testResults.map((ts) => {
  // Strip any absolute prefix to get a relative path (handles both local and CI runner paths)
  let name = ts.name || "";
  const relMatch = name.match(/((?:server|client|shared|drizzle)\/.*$)/);
  name = relMatch ? relMatch[1] : name.replace(ROOT + "/", "");
  // Support both native vitest JSON (assertionResults) and parsed format (numTests)
  if (ts.assertionResults && Array.isArray(ts.assertionResults)) {
    const passed = ts.assertionResults.filter((a) => a.status === "passed").length;
    const failed = ts.assertionResults.filter((a) => a.status === "failed").length;
    const total = ts.assertionResults.length;
    const status = failed > 0 ? "FAIL" : "PASS";
    return { name, total, passed, failed, status };
  } else {
    // Parsed from raw vitest output
    const total = ts.numTests || 0;
    const status = ts.status === "passed" ? "PASS" : "FAIL";
    const passed = status === "PASS" ? total : 0;
    const failed = status === "FAIL" ? total : 0;
    return { name, total, passed, failed, status };
  }
});

// Sort: failures first, then alphabetical
files.sort((a, b) => {
  if (a.failed > 0 && b.failed === 0) return -1;
  if (a.failed === 0 && b.failed > 0) return 1;
  return a.name.localeCompare(b.name);
});

// Failed test details
const failedDetails = [];
for (const ts of report.testResults) {
  if (ts.assertionResults && Array.isArray(ts.assertionResults)) {
    for (const ar of ts.assertionResults) {
      if (ar.status === "failed") {
        failedDetails.push({
          file: (() => { let n = ts.name || ""; const m = n.match(/((?:server|client|shared|drizzle)\/.*$)/); return m ? m[1] : n.replace(ROOT + "/", ""); })(),
          test: ar.fullName,
          message: (ar.failureMessages || []).join("\n").slice(0, 500),
        });
      }
    }
  }
}

// ── Generate markdown ───────────────────────────────────────────────────────
const lines = [];

lines.push("# CI Proof Artifact");
lines.push("");
lines.push("> **This document is machine-generated by `scripts/generate-ci-proof.mjs`**");
lines.push("> from `test-output/vitest.json`. Every number below is extracted from the");
lines.push("> JSON report produced by `vitest --reporter=json`. No hand-written counts.");
lines.push("> To regenerate: `pnpm proof:generate`");
lines.push("");
lines.push("## Source");
lines.push("");
lines.push("| Field | Value |");
lines.push("|-------|-------|");
lines.push(`| JSON artifact | \`test-output/vitest.json\` |`);
lines.push(`| Generated at | ${new Date().toISOString()} |`);
lines.push(`| Test run started | ${startTime} |`);
lines.push(`| Overall success | ${success} |`);
lines.push("");
lines.push("## Summary");
lines.push("");
lines.push("| Metric | Count |");
lines.push("|--------|-------|");
lines.push(`| Test files | ${totalFiles} |`);
lines.push(`| Passed files | ${passedFiles} |`);
lines.push(`| Failed files | ${failedFiles} |`);
lines.push(`| Describe blocks (vitest suites) | ${totalSuites} |`);
lines.push(`| Passed suites | ${passedSuites} |`);
lines.push(`| Failed suites | ${failedSuites} |`);
lines.push(`| Total tests | ${totalTests} |`);
lines.push(`| Passed tests | ${passedTests} |`);
lines.push(`| Failed tests | ${failedTests} |`);
lines.push("");
lines.push("## Per-File Breakdown");
lines.push("");
lines.push("| Status | File | Total | Passed | Failed |");
lines.push("|--------|------|-------|--------|--------|");
for (const f of files) {
  lines.push(`| ${f.status} | \`${f.name}\` | ${f.total} | ${f.passed} | ${f.failed} |`);
}
lines.push("");

if (failedDetails.length > 0) {
  lines.push("## Failed Test Details");
  lines.push("");
  for (const fd of failedDetails) {
    lines.push(`### \`${fd.file}\``);
    lines.push("");
    lines.push(`**Test:** ${fd.test}`);
    lines.push("");
    lines.push("```");
    lines.push(fd.message);
    lines.push("```");
    lines.push("");
  }
}

lines.push("## Reproduction Commands");
lines.push("");
lines.push("```bash");
lines.push("# Generate the JSON artifact");
lines.push("pnpm test -- --run --reporter=json --outputFile.json=test-output/vitest.json");
lines.push("");
lines.push("# Regenerate this proof document from the JSON");
lines.push("pnpm proof:generate");
lines.push("");
lines.push("# Verify this document matches the JSON (no drift)");
lines.push("node scripts/generate-ci-proof.mjs && git diff --exit-code docs/ci-proof-artifact.md");
lines.push("```");
lines.push("");
lines.push("---");
lines.push("");
lines.push("*End of machine-generated proof. Source of truth: `test-output/vitest.json`*");
lines.push("");

writeFileSync(MD_PATH, lines.join("\n"));
console.log(`CI proof artifact written to docs/ci-proof-artifact.md`);
console.log(`  Files:  ${totalFiles} (${passedFiles} passed, ${failedFiles} failed)`);
console.log(`  Suites: ${totalSuites} (${passedSuites} passed, ${failedSuites} failed)`);
console.log(`  Tests:  ${totalTests} (${passedTests} passed, ${failedTests} failed)`);
